const events = [];

for (const item of items) {
  events.push(item.json);
}

let eventRows = '';

for (const event of events) {
  let time = 'All Day';

  if (event.start && event.start.dateTime) {
    const d = new Date(event.start.dateTime);
    let hours = d.getHours();
    let minutes = d.getMinutes();
    const ampm = hours >= 12 ? 'PM' : 'AM';
    hours = hours % 12;
    hours = hours ? hours : 12;
    minutes = minutes < 10 ? '0' + minutes : minutes;
    time = hours + ':' + minutes + ' ' + ampm;
  }

  eventRows += '<div style="background:#f0f8ff; padding:15px; margin:10px 0; border-left:4px solid #4285f4; border-radius:4px;">';
  eventRows += '<h3 style="margin:0; color:#4285f4;">📌 ' + (event.summary || 'No Title') + '</h3>';
  eventRows += '<p><strong>⏰ Time:</strong> ' + time + '</p>';
  eventRows += '<p><strong>📍 Location:</strong> ' + (event.location || 'Not specified') + '</p>';
  eventRows += '<p><strong>📝 Description:</strong> ' + (event.description || 'No description') + '</p>';
  eventRows += '</div>';
}

if (eventRows === '') {
  eventRows = '<p>No events for today!</p>';
}

const html = '<div style="font-family:Arial; max-width:600px; margin:auto;">'
  + '<h2 style="color:#4285f4;">📅 Good Morning Barkavi!</h2>'
  + '<p>Here are all your events for today:</p>'
  + '<hr/>'
  + eventRows
  + '<hr/>'
  + '<p style="color:gray; font-size:12px;">⚡ Sent automatically at 9 AM via n8n workflow</p>'
  + '</div>';

return [{ json: { emailBody: html } }];
